import{Logger}from '../shared/logger.js';export{auth,authGuards,AuthManager}from './auth-service.js';export{leads,clients,projects,campaigns,invoices,deals,content,budget,activities,strategic,seo,workflows,agents,analytics,approvals}from './database-service.js';export{assets,realtime,automation,fileUtils}from './storage-service.js';const TAG='[SupabaseClient]';let clientInstance=null;export function getSupabaseClient(){if(!clientInstance){const url=window.__ENV__?.SUPABASE_URL;const key=window.__ENV__?.SUPABASE_ANON_KEY;if(!url||!key){Logger.error(TAG,'Missing Supabase configuration');throw new Error('SUPABASE_URL and SUPABASE_ANON_KEY are required');}if(typeof window.supabase!=='undefined'&&typeof window.supabase.createClient==='function'){clientInstance=window.supabase.createClient(url,key);}else{Logger.error(TAG,'Supabase CDN not loaded');throw new Error('Supabase client library not loaded');}}return clientInstance;}export const auth={async signIn(email,password){const client=getSupabaseClient();return client.auth.signInWithPassword({email,password});},async signUp(email,password,metadata={}){const client=getSupabaseClient();return client.auth.signUp({email,password,options:{data: metadata}});},async signOut(){const client=getSupabaseClient();return client.auth.signOut();},async getSession(){const client=getSupabaseClient();return client.auth.getSession();},onAuthStateChange(callback){const client=getSupabaseClient();return client.auth.onAuthStateChange(callback);}};export const db={from(table){const client=getSupabaseClient();return client.from(table);},async select(table,columns='*',options={}){const query=this.from(table).select(columns);if(options.eq){query.eq(options.eq.field,options.eq.value);}if(options.order){query.order(options.order.field,{ascending: options.order.ascending ?? true});}return query;},async insert(table,data){return this.from(table).insert(data);},async update(table,data,options){const query=this.from(table).update(data);if(options?.eq){query.eq(options.eq.field,options.eq.value);}return query;},async delete(table,options){const query=this.from(table).delete();if(options?.eq){query.eq(options.eq.field,options.eq.value);}return query;}};export const storage={async upload(bucket,path,file){const client=getSupabaseClient();return client.storage.from(bucket).upload(path,file);},async download(bucket,path){const client=getSupabaseClient();return client.storage.from(bucket).download(path);},async remove(bucket,paths){const client=getSupabaseClient();return client.storage.from(bucket).remove(paths);},getPublicUrl(bucket,path){const client=getSupabaseClient();return client.storage.from(bucket).getPublicUrl(path);}};export const realtime={channels: new Map(),subscribe(channelName,callback){const client=getSupabaseClient();const channel=client.channel(channelName);channel.subscribe(callback);this.channels.set(channelName,channel);return()=>{channel.unsubscribe();this.channels.delete(channelName);};},unsubscribe(channelName){const channel=this.channels.get(channelName);if(channel){channel.unsubscribe();this.channels.delete(channelName);}},unsubscribeAll(){this.channels.forEach(channel=>channel.unsubscribe());this.channels.clear();}};if(typeof document!=='undefined'){document.addEventListener('DOMContentLoaded',()=>{try{getSupabaseClient();Logger.info(TAG,'Supabase client initialized');}catch(e){}});}